import{_ as e,o as r,c as t,a2 as o}from"./chunks/framework.BWuWLRhz.js";const q=JSON.parse('{"title":"常见问题 FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md","lastUpdated":1783294793000}'),l={name:"guide/faq.md"};function i(h,a,n,s,d,c){return r(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="常见问题-faq" tabindex="-1">常见问题 FAQ <a class="header-anchor" href="#常见问题-faq" aria-label="Permalink to &quot;常见问题 FAQ&quot;">​</a></h1><h2 id="连接问题" tabindex="-1">连接问题 <a class="header-anchor" href="#连接问题" aria-label="Permalink to &quot;连接问题&quot;">​</a></h2><h3 id="导入订阅后没有节点" tabindex="-1">导入订阅后没有节点？ <a class="header-anchor" href="#导入订阅后没有节点" aria-label="Permalink to &quot;导入订阅后没有节点？&quot;">​</a></h3><p>按顺序排查：</p><ol><li>在客户端里<strong>手动更新一次订阅</strong>（导入瞬间可能未拉取成功）</li><li>确认账号<strong>套餐有效</strong>：会员中心查看到期时间和剩余流量</li><li>确认订阅链接复制完整（以 <code>https://</code> 开头，中间无空格换行）</li><li>换一个网络环境（如切到手机热点）再更新一次</li></ol><h3 id="节点全部超时-无法连接" tabindex="-1">节点全部超时 / 无法连接？ <a class="header-anchor" href="#节点全部超时-无法连接" aria-label="Permalink to &quot;节点全部超时 / 无法连接？&quot;">​</a></h3><ol><li>更新订阅获取最新节点</li><li>换 2–3 个不同地区的节点分别测试（个别节点可能临时维护）</li><li>检查本机防火墙 / 杀毒软件是否拦截了客户端</li><li>重启客户端，确认&quot;系统代理&quot;已开启</li><li>以上都无效 → <a href="https://freedomport.cc/#/ticket" target="_blank" rel="noreferrer">提交工单</a>，附上客户端日志截图</li></ol><h3 id="连接成功但网页打不开" tabindex="-1">连接成功但网页打不开？ <a class="header-anchor" href="#连接成功但网页打不开" aria-label="Permalink to &quot;连接成功但网页打不开？&quot;">​</a></h3><ul><li>Clash 系确认模式为 <strong>规则（Rule）</strong> 或 <strong>全局（Global）</strong>，且系统代理开关已打开</li><li>浏览器如果装了代理插件（SwitchyOmega 等），检查是否冲突</li><li>尝试清除浏览器 DNS 缓存或更换浏览器验证</li></ul><h3 id="速度慢" tabindex="-1">速度慢？ <a class="header-anchor" href="#速度慢" aria-label="Permalink to &quot;速度慢？&quot;">​</a></h3><ul><li>优先选<strong>低延迟</strong>节点（客户端内测速排序）</li><li>高峰时段（晚 8–11 点）跨境链路普遍拥挤，可尝试不同地区节点</li><li>大流量下载建议走香港 / 日本等近距离节点</li></ul><h2 id="账号与套餐" tabindex="-1">账号与套餐 <a class="header-anchor" href="#账号与套餐" aria-label="Permalink to &quot;账号与套餐&quot;">​</a></h2><h3 id="流量怎么统计-多久刷新" tabindex="-1">流量怎么统计？多久刷新？ <a class="header-anchor" href="#流量怎么统计-多久刷新" aria-label="Permalink to &quot;流量怎么统计？多久刷新？&quot;">​</a></h3><p>上行 + 下行都计入流量。用量数据会回传到会员中心面板，通常几分钟内刷新。</p><h3 id="设备数限制是什么意思" tabindex="-1">设备数限制是什么意思？ <a class="header-anchor" href="#设备数限制是什么意思" aria-label="Permalink to &quot;设备数限制是什么意思？&quot;">​</a></h3><p>指<strong>同时在线</strong>的设备数量。超出限制时新设备会连不上，断开旧设备即可。</p><h3 id="套餐到期-流量用完会怎样" tabindex="-1">套餐到期 / 流量用完会怎样？ <a class="header-anchor" href="#套餐到期-流量用完会怎样" aria-label="Permalink to &quot;套餐到期 / 流量用完会怎样？&quot;">​</a></h3><p>连接会停止，但账号和订阅链接保留。续费或购买流量后<strong>更新订阅</strong>即可恢复，无需重新配置。</p><h3 id="可以退款吗" tabindex="-1">可以退款吗？ <a class="header-anchor" href="#可以退款吗" aria-label="Permalink to &quot;可以退款吗？&quot;">​</a></h3><p>月度套餐满足条件可退，详见<a href="./../policy/terms">使用规范与退款政策</a>。</p><h2 id="客户端选择" tabindex="-1">客户端选择 <a class="header-anchor" href="#客户端选择" aria-label="Permalink to &quot;客户端选择&quot;">​</a></h2><h3 id="我该用哪个客户端" tabindex="-1">我该用哪个客户端？ <a class="header-anchor" href="#我该用哪个客户端" aria-label="Permalink to &quot;我该用哪个客户端？&quot;">​</a></h3><p>看<a href="./getting-started#第三步-导入客户端">快速开始</a>的推荐表。简单说：桌面端用 <strong>Clash Verge Rev</strong>，iOS 用 <strong>Clash Mi</strong>（免费），Android 用 <strong>Clash Meta</strong>。全部下载入口见<a href="./../download">客户端下载</a>。</p><h3 id="ios-应用为什么国区下载不了" tabindex="-1">iOS 应用为什么国区下载不了？ <a class="header-anchor" href="#ios-应用为什么国区下载不了" aria-label="Permalink to &quot;iOS 应用为什么国区下载不了？&quot;">​</a></h3><p>此类应用在国区 App Store 未上架，需要外区 Apple ID 下载。<a href="./../clients/ios/clash-mi">Clash Mi</a> 免费，登录外区 ID 即可安装；<a href="./../clients/ios/shadowrocket">Shadowrocket</a> 为付费备选。</p><h2 id="其他" tabindex="-1">其他 <a class="header-anchor" href="#其他" aria-label="Permalink to &quot;其他&quot;">​</a></h2><h3 id="担心-dns-泄露" tabindex="-1">担心 DNS 泄露？ <a class="header-anchor" href="#担心-dns-泄露" aria-label="Permalink to &quot;担心 DNS 泄露？&quot;">​</a></h3><p>Clash 系客户端开启 <strong>TUN 模式</strong>（或&quot;DNS 劫持&quot;）可以避免大多数 DNS 泄露场景；对隐私要求高的用户建议配合浏览器隐私模式使用。</p><h3 id="还是解决不了" tabindex="-1">还是解决不了？ <a class="header-anchor" href="#还是解决不了" aria-label="Permalink to &quot;还是解决不了？&quot;">​</a></h3><p><a href="https://freedomport.cc/#/ticket" target="_blank" rel="noreferrer">提交工单</a>（描述设备、客户端、节点和报错现象），或通过 <a href="./../support">Telegram 支持</a>联系我们。</p>',30)])])}const f=e(l,[["render",i]]);export{q as __pageData,f as default};
